616   /// Estimate the number of native vector operations for a multiply of matrices
617   /// with dimensions \p R x \p M and \p M x \p C. Native ops are computed as
618   /// ceil(ElementCount * ElementBits / RegisterBits).
619   ///
620   /// Native vector ops per operation type (VF = native vector elements):
621   ///   FMAs:    C * ceil(R/VF) * M (one FMA per VF output elements)
622   ///   A loads: ceil(R/VF) * M (A has M columns, ceil(R/VF) native loads each)
623   ///   B loads: ceil(M/VF) * C (B has C columns, ceil(M/VF) native loads each)
624   ///   Stores:  C * ceil(R/VF) (one store per VF output elements)
625   unsigned getNumNativeVectorOps(Type *EltType, unsigned R, unsigned M,
626                                  unsigned C) {
627     unsigned NumFMAs = C * getNumOps(EltType, R) * M;
628     unsigned NumALoads = getNumOps(EltType, R) * M;
629     unsigned NumBLoads = getNumOps(EltType, M) * C;
630     unsigned NumStores = getNumOps(EltType, R) * C;
631     return NumFMAs + NumALoads + NumBLoads + NumStores;
632   }
