752   /// shapes of operands.
753   SmallVector<Instruction *, 32>
754   propagateShapeForward(SmallVectorImpl<Instruction *> &WorkList) {
755     SmallVector<Instruction *, 32> NewWorkList;
756     // Pop an element for which we guaranteed to have at least one of the
757     // operand shapes.  Add the shape for this and then add users to the work
758     // list.
759     LLVM_DEBUG(dbgs() << "Forward-propagate shapes:\n");
760     while (!WorkList.empty()) {
761       Instruction *Inst = WorkList.pop_back_val();
762 
763       // New entry, set the value and insert operands
764       bool Propagate = false;
765       if (auto SI = computeShapeInfoForInst(Inst, ShapeMap))
766         Propagate = setShapeInfo(Inst, *SI);
767 
768       if (Propagate) {
769         NewWorkList.push_back(Inst);
770         for (auto *User : Inst->users())
771           if (ShapeMap.count(User) == 0)
772             WorkList.push_back(cast<Instruction>(User));
773       }
774     }
775 
776     return NewWorkList;
777   }
