1840       // operand. Then move along the K axes and accumulate the rows.  With this
1841       // the adds can be vectorized without reassociation.
1842       for (unsigned I = 0; I < R; ++I) {
1843         unsigned BlockSize = VF;
1844         bool isSumZero = isa<ConstantAggregateZero>(Result.getRow(I));
1845         for (unsigned J = 0; J < C; J += BlockSize) {
1846           // Lower the vectorization factor to cover the remainder.
1847           BlockSize = capBlockSize(BlockSize, C - J, Result.getElementType());
1848 
1849           Value *Sum = nullptr;
1850           for (unsigned K = 0; K < M; ++K) {
1851             Value *R = B.extractVector(K, J, BlockSize, Builder);
1852             Value *LH = Builder.CreateExtractElement(
1853                 A.getVector(IsScalarMatrixTransposed ? K : I),
1854                 IsScalarMatrixTransposed ? I : K);
1855             Value *Splat = Builder.CreateVectorSplat(BlockSize, LH, "splat");
1856             Sum =
1857                 createMulAdd(isSumZero && K == 0 ? nullptr : Sum, Splat, R,
1858                              IsFP, Builder, FMF.allowContract(), NumComputeOps);
1859           }
1860           Result.setVector(I,
1861                            insertVector(Result.getVector(I), J, Sum, Builder));
1862         }
1863       }
1864     }
1865     Result.addNumComputeOps(NumComputeOps);
1866   }
