1868   /// Ensure that the memory in \p Load does not alias \p Store by potentially
1869   /// copying it to a new location.  This new or otherwise the original location
1870   /// is returned.
1871   Value *getNonAliasingPointer(LoadInst *Load, StoreInst *Store,
1872                                CallInst *MatMul) {
1873     MemoryLocation StoreLoc = MemoryLocation::get(Store);
1874     MemoryLocation LoadLoc = MemoryLocation::get(Load);
1875 
1876     // If we can statically determine noalias we're good.
1877     if (AA->isNoAlias(LoadLoc, StoreLoc))
1878       return Load->getPointerOperand();
1879 
1880     // Create code to check if the memory locations of the Load and Store
1881     // overlap and if they do, copy Load's operand to a new buffer.
1882 
1883     // First, create  new blocks for 2n part of the check and the copy.
1884     BasicBlock *Check0 = MatMul->getParent();
1885     // FIXME: Use lazy DTU and update SplitBlock to accept a DTU instead of a
1886     // DT. Manually collect dominator tree updates, to avoid unnecessary work,
1887     // as we adjust Check0 and Check1's branches.
1888     SmallVector<DominatorTree::UpdateType, 4> DTUpdates;
1889     for (BasicBlock *Succ : successors(Check0))
1890       DTUpdates.push_back({DT->Delete, Check0, Succ});
1891 
1892     BasicBlock *Check1 =
1893         SplitBlock(MatMul->getParent(), MatMul, (DomTreeUpdater *)nullptr, LI,
1894                    nullptr, "alias_cont");
1895     BasicBlock *Copy =
1896         SplitBlock(MatMul->getParent(), MatMul, (DomTreeUpdater *)nullptr, LI,
1897                    nullptr, "copy");
1898     BasicBlock *Fusion =
1899         SplitBlock(MatMul->getParent(), MatMul, (DomTreeUpdater *)nullptr, LI,
1900                    nullptr, "no_alias");
1901 
1902     // Check if the loaded memory location begins before the end of the store
1903     // location. If the condition holds, they might overlap, otherwise they are
1904     // guaranteed to not overlap.
1905     IRBuilder<> Builder(MatMul);
1906     Check0->getTerminator()->eraseFromParent();
1907     Builder.SetInsertPoint(Check0);
1908     Type *IntPtrTy = Builder.getIntPtrTy(Load->getDataLayout());
1909     Value *StoreBegin = Builder.CreatePtrToInt(
1910         const_cast<Value *>(StoreLoc.Ptr), IntPtrTy, "store.begin");
1911     Value *StoreEnd = Builder.CreateAdd(
1912         StoreBegin, ConstantInt::get(IntPtrTy, StoreLoc.Size.getValue()),
1913         "store.end", true, true);
1914     Value *LoadBegin = Builder.CreatePtrToInt(const_cast<Value *>(LoadLoc.Ptr),
1915                                               IntPtrTy, "load.begin");
1916     Builder.CreateCondBr(Builder.CreateICmpULT(LoadBegin, StoreEnd), Check1,
1917                          Fusion);
1918 
1919     // Check if the store begins before the end of the load location. If the
1920     // condition holds, they alias, otherwise they are guaranteed to not
1921     // overlap.
1922     Check1->getTerminator()->eraseFromParent();
1923     Builder.SetInsertPoint(Check1, Check1->begin());
1924     Value *LoadEnd = Builder.CreateAdd(
1925         LoadBegin, ConstantInt::get(IntPtrTy, LoadLoc.Size.getValue()),
1926         "load.end", true, true);
1927     Builder.CreateCondBr(Builder.CreateICmpULT(StoreBegin, LoadEnd), Copy,
1928                          Fusion);
1929 
1930     // Copy load operand to new alloca.
1931     Builder.SetInsertPoint(Copy, Copy->begin());
1932     auto *VT = cast<FixedVectorType>(Load->getType());
1933     // Use an array type for the alloca, to avoid potentially huge alignment
1934     // requirements for large vector types.
1935     auto *ArrayTy = ArrayType::get(VT->getElementType(), VT->getNumElements());
1936     AllocaInst *Alloca =
1937         Builder.CreateAlloca(ArrayTy, Load->getPointerAddressSpace());
1938 
1939     Builder.CreateMemCpy(Alloca, Alloca->getAlign(), Load->getPointerOperand(),
1940                          Load->getAlign(), LoadLoc.Size.getValue());
1941     Builder.SetInsertPoint(Fusion, Fusion->begin());
1942     PHINode *PHI = Builder.CreatePHI(Load->getPointerOperandType(), 3);
1943     PHI->addIncoming(Load->getPointerOperand(), Check0);
1944     PHI->addIncoming(Load->getPointerOperand(), Check1);
1945     PHI->addIncoming(Alloca, Copy);
1946 
1947     // Adjust DT.
1948     DTUpdates.push_back({DT->Insert, Check0, Check1});
1949     DTUpdates.push_back({DT->Insert, Check0, Fusion});
1950     DTUpdates.push_back({DT->Insert, Check1, Copy});
1951     DTUpdates.push_back({DT->Insert, Check1, Fusion});
1952     DT->applyUpdates(DTUpdates);
1953     return PHI;
1954   }
