1956   bool isFusionProfitable(CallInst *MatMul) {
1957     if (ForceFusion)
1958       return true;
1959 
1960     ShapeInfo LShape(MatMul->getArgOperand(2), MatMul->getArgOperand(3));
1961     ShapeInfo RShape(MatMul->getArgOperand(3), MatMul->getArgOperand(4));
1962 
1963     const unsigned R = LShape.NumRows;
1964     const unsigned C = RShape.NumColumns;
1965     const unsigned M = LShape.NumColumns;
1966     auto *EltType = cast<FixedVectorType>(MatMul->getType())->getElementType();
1967 
1968     const unsigned VF = std::max<unsigned>(
1969         TTI.getRegisterBitWidth(TargetTransformInfo::RGK_FixedWidthVector)
1970                 .getFixedValue() /
1971             EltType->getPrimitiveSizeInBits().getFixedValue(),
1972         1U);
1973 
1974     // Cost model for tiling
1975     //
1976     // For tiling to be beneficial, we need reuse either along the R or
1977     // the C axis.  We vectorize along the R axis so that means at least
1978     // 3 elements.
1979     // TODO: Also consider cost of copying if operands alias.
1980     if (R <= VF && C == 1)
1981       return false;
1982     // Then we need enough elements to exceed the number of vector
1983     // registers we have.  Note that this is an oversimplification since
1984     // fusing also takes some extra loads which may exceed the number of
1985     // reloads necessary.
1986     unsigned Op0Regs = (R + VF - 1) / VF * M;
1987     unsigned Op1Regs = (M + VF - 1) / VF * C;
1988     return Op0Regs + Op1Regs >
1989            TTI.getNumberOfRegisters(TTI.getRegisterClassForType(true));
1990   }
