2000   void createTiledLoops(CallInst *MatMul, Value *LPtr, ShapeInfo LShape,
2001                         Value *RPtr, ShapeInfo RShape, StoreInst *Store) {
2002     auto *EltType = cast<FixedVectorType>(MatMul->getType())->getElementType();
2003 
2004     // Create the main tiling loop nest.
2005     TileInfo TI(LShape.NumRows, RShape.NumColumns, LShape.NumColumns, TileSize);
2006     DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Lazy);
2007     Instruction *InsertI = cast<Instruction>(MatMul);
2008     BasicBlock *Start = InsertI->getParent();
2009     BasicBlock *End =
2010         SplitBlock(InsertI->getParent(), InsertI, DT, LI, nullptr, "continue");
2011     IRBuilder<> Builder(MatMul);
2012     BasicBlock *InnerBody = TI.CreateTiledLoops(Start, End, Builder, DTU, *LI);
2013 
2014     Type *TileVecTy =
2015         FixedVectorType::get(MatMul->getType()->getScalarType(), TileSize);
2016     MatrixTy TileResult;
2017     // Insert in the inner loop header.
2018     Builder.SetInsertPoint(TI.KLoop.Header->getTerminator());
2019     // Create PHI nodes for the result columns to accumulate across iterations.
2020     SmallVector<PHINode *, 4> ColumnPhis;
2021     for (unsigned I = 0; I < TileSize; I++) {
2022       auto *Phi = Builder.CreatePHI(TileVecTy, 2, "result.vec." + Twine(I));
2023       Phi->addIncoming(ConstantAggregateZero::get(TileVecTy),
2024                        TI.RowLoop.Header->getSingleSuccessor());
2025       TileResult.addVector(Phi);
2026       ColumnPhis.push_back(Phi);
2027     }
2028 
2029     // Insert in the inner loop body, which computes
2030     //   Res += Load(CurrentRow, K) * Load(K, CurrentColumn)
2031     Builder.SetInsertPoint(InnerBody->getTerminator());
2032     // Load tiles of the operands.
2033     MatrixTy A =
2034         loadMatrix(LPtr, {}, false, LShape, TI.RowLoop.Index, TI.KLoop.Index,
2035                    {TileSize, TileSize}, EltType, Builder);
2036     MatrixTy B =
2037         loadMatrix(RPtr, {}, false, RShape, TI.KLoop.Index, TI.ColumnLoop.Index,
2038                    {TileSize, TileSize}, EltType, Builder);
2039     emitMatrixMultiply(TileResult, A, B, Builder, true, false,
2040                        getFastMathFlags(MatMul));
2041     // Store result after the inner loop is done.
2042     Builder.SetInsertPoint(TI.RowLoop.Latch->getTerminator());
2043     storeMatrix(TileResult, Store->getPointerOperand(), Store->getAlign(),
2044                 Store->isVolatile(), {LShape.NumRows, RShape.NumColumns},
2045                 TI.RowLoop.Index, TI.ColumnLoop.Index, EltType, Builder);
2046 
2047     for (unsigned I = 0; I < TileResult.getNumVectors(); I++)
2048       ColumnPhis[I]->addIncoming(TileResult.getVector(I), TI.KLoop.Latch);
2049 
