634   /// Return the set of vectors that a matrix value is lowered to.
635   ///
636   /// If we lowered \p MatrixVal, just return the cache result matrix. Otherwise
637   /// split the flat vector \p MatrixVal containing a matrix with shape \p SI
638   /// into vectors.
639   MatrixTy getMatrix(Value *MatrixVal, const ShapeInfo &SI,
640                      IRBuilder<> &Builder) {
641     FixedVectorType *VType = cast<FixedVectorType>(MatrixVal->getType());
642     assert(VType->getNumElements() == SI.NumRows * SI.NumColumns &&
643            "The vector size must match the number of matrix elements");
644 
645     // Check if we lowered MatrixVal using shape information. In that case,
646     // return the existing matrix, if it matches the requested shape
647     // information. If there is a mis-match, embed the result in a flat
648     // vector and split it later.
649     auto Found = Inst2ColumnMatrix.find(MatrixVal);
650     if (Found != Inst2ColumnMatrix.end()) {
651       MatrixTy &M = Found->second;
652       // Return the found matrix, if its shape matches the requested shape
653       // information
654       if (SI.NumRows == M.getNumRows() && SI.NumColumns == M.getNumColumns())
655         return M;
656 
657       MatrixVal = M.embedInVector(Builder);
658     }
659 
660     // Otherwise split MatrixVal.
661     SmallVector<Value *, 16> SplitVecs;
662     for (unsigned MaskStart = 0; MaskStart < VType->getNumElements();
663          MaskStart += SI.getStride()) {
664       Value *V = Builder.CreateShuffleVector(
665           MatrixVal, createSequentialMask(MaskStart, SI.getStride(), 0),
666           "split");
667       SplitVecs.push_back(V);
668     }
669 
670     if (Instruction *Inst = dyn_cast<Instruction>(MatrixVal)) {
671       if (Found != Inst2ColumnMatrix.end()) {
672         // FIXME: re: "at least": SplitVecs.size() doesn't count the shuffles
673         // that embedInVector created.
674         LLVM_DEBUG(dbgs() << "matrix reshape from " << Found->second.shape()
675                           << " to " << SI << " using at least "
676                           << SplitVecs.size() << " shuffles on behalf of:\n"
677                           << *Inst << '\n');
678         ReshapedMatrices++;
679       } else if (!ShapeMap.contains(MatrixVal)) {
680         LLVM_DEBUG(
681             dbgs()
682             << "splitting a " << SI << " matrix with " << SplitVecs.size()
683             << " shuffles beacuse we do not have a shape-aware lowering for "
684                "its def:\n"
685             << *Inst << '\n');
686         (void)Inst;
687         SplitMatrices++;
688       } else {
689         // The ShapeMap has it, so it's a case where we're being lowered
690         // before the def, and we expect that InstCombine will clean things up
691         // afterward.
692       }
693     }
694 
695     return {SplitVecs};
696   }
