698   /// If \p V already has a known shape return false.  Otherwise set the shape
699   /// for instructions that support it.
700   bool setShapeInfo(Value *V, ShapeInfo Shape) {
701     assert(Shape && "Shape not set");
702     if (isa<UndefValue>(V) || !supportsShapeInfo(V))
703       return false;
704 
705     auto SIter = ShapeMap.find(V);
706     if (SIter != ShapeMap.end()) {
707       if (VerifyShapeInfo && (SIter->second.NumRows != Shape.NumRows ||
708                               SIter->second.NumColumns != Shape.NumColumns)) {
709         errs() << "Conflicting shapes (" << SIter->second.NumRows << "x"
710                << SIter->second.NumColumns << " vs " << Shape.NumRows << "x"
711                << Shape.NumColumns << ") for " << *V << "\n";
712         report_fatal_error(
713             "Matrix shape verification failed, compilation aborted!");
714       }
715 
716       LLVM_DEBUG(dbgs() << "  not overriding existing shape: "
717                         << SIter->second.NumRows << " "
718                         << SIter->second.NumColumns << " for " << *V << "\n");
719       return false;
720     }
721 
722     ShapeMap.insert({V, Shape});
723     LLVM_DEBUG(dbgs() << "  " << Shape.NumRows << " x " << Shape.NumColumns
724                       << " for " << *V << "\n");
725     return true;
726   }
