728   /// Returns true if shape information can be used for \p V. The supported
729   /// instructions must match the instructions that can be lowered by this pass.
730   bool supportsShapeInfo(Value *V) {
731     Instruction *Inst = dyn_cast<Instruction>(V);
732     if (!Inst)
733       return false;
734 
735     IntrinsicInst *II = dyn_cast<IntrinsicInst>(Inst);
736     if (II)
737       switch (II->getIntrinsicID()) {
738       case Intrinsic::matrix_multiply:
739       case Intrinsic::matrix_transpose:
740       case Intrinsic::matrix_column_major_load:
741       case Intrinsic::matrix_column_major_store:
742         return true;
743       default:
744         break;
745       }
746     return isShapePreserving(V) || isa<StoreInst>(V) || isa<LoadInst>(V);
747   }
