779   /// Propagate the shape to operands of instructions with shape information.
780   /// \p Worklist contains the instruction for which we already know the shape.
781   SmallVector<Instruction *, 32>
782   propagateShapeBackward(SmallVectorImpl<Instruction *> &WorkList) {
783     SmallVector<Instruction *, 32> NewWorkList;
784 
785     auto pushInstruction = [](Value *V,
786                               SmallVectorImpl<Instruction *> &WorkList) {
787       Instruction *I = dyn_cast<Instruction>(V);
788       if (I)
789         WorkList.push_back(I);
790     };
791     // Pop an element with known shape.  Traverse the operands, if their shape
792     // derives from the result shape and is unknown, add it and add them to the
793     // worklist.
794     LLVM_DEBUG(dbgs() << "Backward-propagate shapes:\n");
795     while (!WorkList.empty()) {
796       Value *V = WorkList.pop_back_val();
797 
798       size_t BeforeProcessingV = WorkList.size();
799       if (!isa<Instruction>(V))
800         continue;
801 
802       Value *MatrixA;
803       Value *MatrixB;
804       Value *M;
805       Value *N;
806       Value *K;
807       if (match(V, m_Intrinsic<Intrinsic::matrix_multiply>(
808                        m_Value(MatrixA), m_Value(MatrixB), m_Value(M),
809                        m_Value(N), m_Value(K)))) {
810         if (setShapeInfo(MatrixA, {M, N}))
811           pushInstruction(MatrixA, WorkList);
812 
813         if (setShapeInfo(MatrixB, {N, K}))
814           pushInstruction(MatrixB, WorkList);
815 
816       } else if (match(V, m_Intrinsic<Intrinsic::matrix_transpose>(
817                               m_Value(MatrixA), m_Value(M), m_Value(N)))) {
818         // Flip dimensions.
819         if (setShapeInfo(MatrixA, {M, N}))
820           pushInstruction(MatrixA, WorkList);
821       } else if (match(V, m_Intrinsic<Intrinsic::matrix_column_major_store>(
822                               m_Value(MatrixA), m_Value(), m_Value(), m_Value(),
823                               m_Value(M), m_Value(N)))) {
824         if (setShapeInfo(MatrixA, {M, N})) {
825           pushInstruction(MatrixA, WorkList);
826         }
827       } else if (isa<LoadInst>(V) ||
828                  match(V, m_Intrinsic<Intrinsic::matrix_column_major_load>())) {
829         // Nothing to do, no matrix input.
830       } else if (isa<StoreInst>(V)) {
831         // Nothing to do.  We forward-propagated to this so we would just
832         // backward propagate to an instruction with an already known shape.
833       } else if (isShapePreserving(V)) {
834         auto ShapedOps = getShapedOperandsForInst(cast<Instruction>(V));
835         // Propagate to all operands.
836         ShapeInfo Shape = ShapeMap[V];
837         for (Use &U : ShapedOps) {
838           if (setShapeInfo(U.get(), Shape))
839             pushInstruction(U.get(), WorkList);
840         }
841       }
842       // After we discovered new shape info for new instructions in the
843       // worklist, we use their users as seeds for the next round of forward
844       // propagation.
845       for (size_t I = BeforeProcessingV; I != WorkList.size(); I++)
846         for (User *U : WorkList[I]->users())
847           if (isa<Instruction>(U) && V != U)
848             NewWorkList.push_back(cast<Instruction>(U));
849     }
